package com.hogaria.exception; import jakarta.servlet.http.HttpServletRequest; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.time.OffsetDateTime; @RestControllerAdvice public class GlobalExceptionHandler { @ExceptionHandler({BadRequestException.class,IllegalArgumentException.class}) ResponseEntity<ErrorResponse> bad(RuntimeException ex,HttpServletRequest req){return build(HttpStatus.BAD_REQUEST,ex,req);} @ExceptionHandler(NotFoundException.class) ResponseEntity<ErrorResponse> nf(NotFoundException ex,HttpServletRequest req){return build(HttpStatus.NOT_FOUND,ex,req);} @ExceptionHandler(ForbiddenException.class) ResponseEntity<ErrorResponse> fb(ForbiddenException ex,HttpServletRequest req){return build(HttpStatus.FORBIDDEN,ex,req);} private ResponseEntity<ErrorResponse> build(HttpStatus s,RuntimeException ex,HttpServletRequest req){return ResponseEntity.status(s).body(new ErrorResponse(OffsetDateTime.now(),s.value(),s.getReasonPhrase(),ex.getMessage(),req.getRequestURI()));}}
